mapper.select:
SELECT gsr.id, gsr.sender_id as senderId, sender.user_name as senderName, gsr.receiver_id as receiverId, receiver.user_name as receiverName, gsr.live_room_id as liveRoomId, lr.title as liveRoomTitle, gsr.gift_id as giftId, g.name as giftName, g.image_url as giftImageUrl, gsr.quantity, g.price as unitPrice, gsr.total_price as totalPrice, gsr.created_at as createdAt, DATE_FORMAT(gsr.created_at, '%Y-%m-%d %H:%i:%s') as createdAtFormatted FROM gift_send_record gsr LEFT JOIN sys_user sender ON gsr.sender_id = sender.id LEFT JOIN sys_user receiver ON gsr.receiver_id = receiver.id LEFT JOIN live_room lr ON gsr.live_room_id = lr.id LEFT JOIN gift g ON gsr.gift_id = g.id
AND gsr.sender_id = #{query.senderId}
AND sender.user_name LIKE CONCAT('%', #{query.senderName}, '%')
AND gsr.receiver_id = #{query.receiverId}
AND receiver.user_name LIKE CONCAT('%', #{query.receiverName}, '%')
AND gsr.live_room_id = #{query.liveRoomId}
AND gsr.gift_id = #{query.giftId}
AND g.name LIKE CONCAT('%', #{query.giftName}, '%')
AND gsr.created_at >= #{query.createdAtStart}
AND gsr.created_at <= #{query.createdAtEnd}
ORDER BY gsr.created_at DESC
